import React, { useState } from "react";
import {
  Box, Button, Container, TextField, Typography, ToggleButton, ToggleButtonGroup,
  Paper, Alert, CircularProgress
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "", role: "user" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = (e) => setFormData(p => ({ ...p, [e.target.name]: e.target.value }));
  const handleRoleChange = (_, newRole) => newRole && setFormData(p => ({ ...p, role: newRole }));

  const validate = () => {
    const mobileRegex = /^[6-9]\d{9}$/;
    if (!formData.fullName || formData.fullName.length < 2) { setError("Enter valid name"); return false; }
    if (!/\S+@\S+\.\S+/.test(formData.email)) { setError("Enter valid email"); return false; }
    if (!mobileRegex.test(formData.mobile)) { setError("Mobile must start with 6-9 and 10 digits"); return false; }
    setError(""); return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/auth/signup", formData);
      if (res.data.success) {
        setSuccess(res.data.message);
        setTimeout(() => navigate("/login"), 700);
      } else setError(res.data.message || "Signup failed");
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered" }}>Rider App</Typography>
        <Typography variant="body1" align="center" sx={{ mb: 3 }}>Create your account</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" required />
          <TextField fullWidth label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" required />
          <TextField fullWidth label="Mobile Number" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" inputProps={{ maxLength: 10 }} required />

          <Typography variant="subtitle1" sx={{ mt: 2 }}>Role</Typography>
          <ToggleButtonGroup value={formData.role} exclusive onChange={handleRoleChange} fullWidth sx={{ mb: 2 }}>
            <ToggleButton value="user">User</ToggleButton>
            <ToggleButton value="owner">Owner</ToggleButton>
          </ToggleButtonGroup>

          <Button type="submit" fullWidth variant="contained" sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }} disabled={loading}>
            {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Register"}
          </Button>
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Already have an account? <Button variant="text" onClick={() => navigate("/login")} sx={{ color: "orangered" }}>Login</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
